// ============================================================
// EXTRACT STATUS CHANGE EVENT FROM JIRA WEBHOOK
// ============================================================
const body = $input.item.json.body || $input.item.json;
const issue = body.issue || {};
const fields = issue.fields || {};
const changelog = body.changelog || {};
const changelogItems = changelog.items || [];

const key = issue.key || '';
const projectKey = (fields.project && fields.project.key) || key.split('-')[0];

// Only process REQ project
if (projectKey !== 'REQ') {
  return [{ json: { skip: true, reason: 'Not a REQ ticket', key } }];
}

// Find the status change item
const statusChange = changelogItems.find(item => item.field === 'status');
if (!statusChange) {
  return [{ json: { skip: true, reason: 'No status change found', key } }];
}

const fromStatus = statusChange.fromString || '';
const toStatus = statusChange.toString || '';
const changedAt = body.timestamp
  ? new Date(body.timestamp).toISOString().split('T')[0]
  : new Date().toISOString().split('T')[0];

const summary = fields.summary || '';
const issueType = (fields.issuetype && fields.issuetype.name) || '';
const assignee = (fields.assignee && fields.assignee.displayName) || '';
const jiraUrl = `https://arduasolutions.atlassian.net/browse/${key}`;

let tipo = 'REQ';
if (issueType === 'Task' || issueType === 'TASK') tipo = 'TASK';

// Determine responsable for each status
const getResponsable = (status) => {
  const producto = ['BACKLOG', 'IN ANALYSIS', 'In Progress', 'Blocked'];
  const it = ['SENT TO DEV', 'Ready for Dev', 'In Development'];
  if (it.includes(status)) return 'IT';
  if (['Done', 'DEPRECATED'].includes(status)) return 'Ninguno';
  return 'Producto';
};

return [{
  json: {
    skip: false,
    key,
    summary,
    tipo,
    fromStatus,
    toStatus,
    changedAt,
    assignee,
    jiraUrl,
    responsableFromStatus: getResponsable(fromStatus),
    responsableToStatus: getResponsable(toStatus)
  }
}];

// ============================================================
// CALCULATE DAYS IN PREVIOUS STATUS & BUILD PAYLOADS
// ============================================================
const notionResults = $input.item.json.results || [];
const extract = $('Extract Status Change').item.json;

if (notionResults.length === 0) {
  return [{ json: { skip: true, reason: 'Ticket not found in Notion', key: extract.key } }];
}

const page = notionResults[0];
const pageId = page.id;
const props = page.properties || {};

// Get fecha entrada of the FROM status to calculate days spent
const statusToFechaField = {
  'BACKLOG':        'Fecha entrada BACKLOG',
  'IN ANALYSIS':    'Fecha entrada IN ANALYSIS',
  'In Progress':    'Fecha entrada In Progress',
  'Blocked':        'Fecha entrada Blocked',
  'SENT TO DEV':    'Fecha entrada SENT TO DEV',
  'Ready for Dev':  'Fecha entrada Ready for Dev',
  'In Development': 'Fecha entrada In Development',
  'Done':           'Fecha entrada Done',
  'DEPRECATED':     'Fecha entrada DEPRECATED'
};

const statusToDiasField = {
  'BACKLOG':        'Días en BACKLOG',
  'IN ANALYSIS':    'Días en IN ANALYSIS',
  'In Progress':    'Días en In Progress',
  'Blocked':        'Días en Blocked',
  'SENT TO DEV':    'Días en SENT TO DEV',
  'Ready for Dev':  'Días en Ready for Dev',
  'In Development': 'Días en In Development',
  'Done':           'Días en Done',
  'DEPRECATED':     'Días en DEPRECATED'
};

// Calculate days in fromStatus
const fromFechaKey = statusToFechaField[extract.fromStatus];
let diasEnEstadoAnterior = 0;

if (fromFechaKey && props[fromFechaKey] && props[fromFechaKey].date && props[fromFechaKey].date.start) {
  const fechaEntrada = new Date(props[fromFechaKey].date.start);
  const fechaSalida = new Date(extract.changedAt);
  const diffMs = fechaSalida - fechaEntrada;
  diasEnEstadoAnterior = Math.max(0, Math.round(diffMs / (1000 * 60 * 60 * 24)));
}

// Build update properties for SLA — Tickets PRODUCTS
const updateProperties = {};

// Update current status
updateProperties['Estado Actual'] = { select: { name: extract.toStatus } };
updateProperties['Responsable'] = { select: { name: extract.responsableToStatus } };
updateProperties['IT es responsable'] = { checkbox: extract.responsableToStatus === 'IT' };
updateProperties['Última Actualización'] = { date: { start: extract.changedAt } };
updateProperties['Días en Estado Actual'] = { number: 0 };

// Update dias en fromStatus
const diasFromKey = statusToDiasField[extract.fromStatus];
if (diasFromKey) {
  updateProperties[diasFromKey] = { number: diasEnEstadoAnterior };
}

// Set fecha entrada for toStatus
const fechaToKey = statusToFechaField[extract.toStatus];
if (fechaToKey) {
  updateProperties[fechaToKey] = { date: { start: extract.changedAt } };
}

// Build changelog entry properties
const transitionId = `${extract.key}-${extract.fromStatus}-${extract.toStatus}-${extract.changedAt}`;

const changelogProperties = {
  'ID Transición': { title: [{ text: { content: transitionId } }] },
  'Ticket Key': { rich_text: [{ text: { content: extract.key } }] },
  'Tipo': { select: { name: extract.tipo } },
  'Estado Anterior': { rich_text: [{ text: { content: extract.fromStatus } }] },
  'Estado Nuevo': { rich_text: [{ text: { content: extract.toStatus } }] },
  'Responsable Estado Anterior': { select: { name: extract.responsableFromStatus } },
  'Responsable Estado Nuevo': { select: { name: extract.responsableToStatus } },
  'Fecha Entrada': { date: { start: fromFechaKey && props[fromFechaKey] && props[fromFechaKey].date ? props[fromFechaKey].date.start : extract.changedAt } },
  'Fecha Salida': { date: { start: extract.changedAt } },
  'Días en Estado': { number: diasEnEstadoAnterior },
  'URL Jira': { url: extract.jiraUrl }
};

return [{
  json: {
    skip: false,
    pageId,
    updateProperties,
    changelogProperties,
    key: extract.key
  }
}];
